record.field:
for rec in records:
    if (
        (rec.x_intake_phase == 'prescreening' and rec.x_chairman_decision == 'pending')
        or (rec.x_intake_phase == 'pooling' and rec.x_chairman_decision == 'rejected')
    ):
        rec.write({
            'x_chairman_decision': 'approved',
            'x_intake_phase': 'pooling',
        })
        rec.message_post(body='Chairman approved candidate into pooling.')

for rec in records:
    if rec.x_intake_phase == 'pooling' and rec.x_chairman_decision == 'approved':
        rec.write({
            'x_chairman_decision': 'on_hold',
            'x_intake_phase': 'pooling',
        })
        rec.message_post(body='Chairman put candidate on hold.')

for rec in records:
    if rec.x_intake_phase in ('prescreening', 'pooling') and rec.x_chairman_decision in ('pending', 'approved', 'on_hold'):
        rec.write({
            'x_chairman_decision': 'rejected',
            'x_intake_phase': 'pooling',
        })
        rec.message_post(body='Chairman rejected candidate.')
